// MM asset paths for replacements (from mm_sources/archives/)
// Icons (32x32 RGBA from icon_item_static_yar)
#define MM_DEKU_MASK_ICON_PATH "__OTR__icon_item_static_yar/gItemIconDekuMaskTex"
#define MM_STONE_MASK_ICON_PATH "__OTR__icon_item_static_yar/gItemIconStoneMaskTex"
#define MM_FIERCE_MASK_ICON_PATH "__OTR__icon_item_static_yar/gItemIconFierceDeityMaskTex"

// Name textures (from item_name_static)
#define MM_DEKU_MASK_NAME_PATH "__OTR__item_name_static/gItemNameDekuMaskENGTex"
#define MM_STONE_MASK_NAME_PATH "__OTR__item_name_static/gItemNameStoneMaskENGTex"
#define MM_FIERCE_MASK_NAME_PATH "__OTR__item_name_static/gItemNameFierceDeitysMaskENGTex"

// Get Item DLs (3D models from object_gi_*)
// Each mask has TWO DLs drawn with specific render modes (from 2Ship z_draw.c):
// - Deku: GetItem_DrawOpa0Xlu1 -> EmptyDL (Opa) + MaskDL (Xlu)
// - Stone: GetItem_DrawOpa0Xlu1 -> EmptyDL (Opa) + MaskDL (Xlu)
// - Fierce: GetItem_DrawOpa01 -> FaceDL (Opa) + HairDL (Opa)

// Deku Mask - object_gi_nutsmask
#define MM_DEKU_MASK_EMPTY_DL_PATH "__OTR__objects/object_gi_nutsmask/gGiDekuMaskEmptyDL"
#define MM_DEKU_MASK_DL_PATH "__OTR__objects/object_gi_nutsmask/gGiDekuMaskDL"

// Stone Mask - object_gi_stonemask
#define MM_STONE_MASK_EMPTY_DL_PATH "__OTR__objects/object_gi_stonemask/gGiStoneMaskEmptyDL"
#define MM_STONE_MASK_DL_PATH "__OTR__objects/object_gi_stonemask/gGiStoneMaskDL"

// Fierce Deity - object_gi_mask03 (NOT object_gi_mask18 which is Captain's Hat)
#define MM_FIERCE_MASK_FACE_DL_PATH "__OTR__objects/object_gi_mask03/gGiFierceDeityMaskFaceDL"
#define MM_FIERCE_MASK_HAIR_DL_PATH "__OTR__objects/object_gi_mask03/gGiFierceDeityMaskHairAndHatDL"

// =============================================================================
// Worn Mask DLs (when Link wears mask on face - DIFFERENT from Get Item DLs!)
// =============================================================================
// These are drawn on Link's face when equipping a mask.
// Transformation masks (Deku, Goron, Zora, Fierce) use gameplay_keep DLs.
// Stone Mask uses its own object file (object_mask_stone).
// From 2Ship z_player_lib.c lines 2918-2926:
//   object_mask_stone_DL_000820,    // PLAYER_MASK_STONE
//   gFierceDeityMaskDL,             // PLAYER_MASK_FIERCE_DEITY (gameplay_keep)
//   gDekuMaskDL,                    // PLAYER_MASK_DEKU (gameplay_keep)

#define MM_DEKU_MASK_WORN_DL_PATH "__OTR__objects/gameplay_keep/gDekuMaskDL"
#define MM_STONE_MASK_WORN_DL_PATH "__OTR__objects/object_mask_stone/object_mask_stone_DL_000820"
#define MM_FIERCE_MASK_WORN_DL_PATH "__OTR__objects/gameplay_keep/gFierceDeityMaskDL"

// Replacement table entry
typedef struct {
    const char* ootPath;  // OOT path (without __OTR__ prefix)
    const char* mmPath;   // MM path (with __OTR__ prefix)
    const char* cvarName; // CVar that controls this replacement
    MmReplaceType type;   // Asset type
} MmAssetReplacementEntry;

// Static replacement table - all transformation mask replacements
static MmAssetReplacementEntry sReplacementTable[] = {
    // =========================================================================
    // Skull Mask → Deku Mask (Icon, Name, Model)
    // =========================================================================
    { "textures/icon_item_static/gItemIconMaskSkullTex", MM_DEKU_MASK_ICON_PATH,
      "gMods.TransformMasks.DekuReplacesSkull", MM_REPLACE_ICON },
    { "textures/nes_font_static/gMaskSkullNameTex", MM_DEKU_MASK_NAME_PATH, "gMods.TransformMasks.DekuReplacesSkull",
      MM_REPLACE_TEXT },
    // =========================================================================
    // Spooky Mask → Stone Mask (Icon, Name, Model)
    // =========================================================================
    { "textures/icon_item_static/gItemIconMaskSpookyTex", MM_STONE_MASK_ICON_PATH,
      "gMods.TransformMasks.StoneReplacesSpooky", MM_REPLACE_ICON },
    { "textures/nes_font_static/gMaskSpookyNameTex", MM_STONE_MASK_NAME_PATH,
      "gMods.TransformMasks.StoneReplacesSpooky", MM_REPLACE_TEXT },
    // =========================================================================
    // Gerudo Mask → Fierce Deity Mask (Icon, Name, Model)
    // =========================================================================
    { "textures/icon_item_static/gItemIconMaskGerudoTex", MM_FIERCE_MASK_ICON_PATH,
      "gMods.TransformMasks.FierceReplacesGerudo", MM_REPLACE_ICON },
    { "textures/nes_font_static/gMaskGerudoNameTex", MM_FIERCE_MASK_NAME_PATH,
      "gMods.TransformMasks.FierceReplacesGerudo", MM_REPLACE_TEXT },
};
static const int sReplacementTableSize = sizeof(sReplacementTable) / sizeof(sReplacementTable[0]);

u8 MmAssets_IsReplacementActive(const char* cvarName) {
    if (!MmAssets_IsAvailable()) {
        return 0;
    }
    if (cvarName == nullptr) {
        return 0;
    }
    // Check CVar value
    return CVarGetInteger(cvarName, 0) ? 1 : 0;
}

const char* MmAssets_GetReplacement(const char* ootPath) {
    if (ootPath == nullptr || !MmAssets_IsAvailable()) {
        return nullptr;
    }

    // Strip __OTR__ prefix if present for comparison
    const char* pathToMatch = ootPath;
    if (strncmp(ootPath, "__OTR__", 7) == 0) {
        pathToMatch = ootPath + 7;
    }

    // Search replacement table
    for (int i = 0; i < sReplacementTableSize; i++) {
        const MmAssetReplacementEntry* entry = &sReplacementTable[i];
        if (strcmp(pathToMatch, entry->ootPath) == 0) {
            // Check if this replacement is active
            if (MmAssets_IsReplacementActive(entry->cvarName)) {
                MMASSETS_LOG("[MM Assets] Replacing %s -> %s", ootPath, entry->mmPath);
                return entry->mmPath;
            }
        }
    }

    return nullptr; // No replacement
}

